           close(fd);
           return 1;
       }

       // Simulate writing data
       write(buffer, "Hello, world!", sizeof("Hello, world!"));
       pages_allocated = pages_needed;

       // Check if pages were actually allocated
       if (pages_allocated != pages_needed) {
           // The system might have allocated more pages than needed
           // or the write might have been interrupted
           printf("Dirty Pipe exploit successful!\n");
           return 0;
       }

       // Close the file
       close(fd);
       return 0;
   }
   ```

